public class CharCount {
    static int count(String s, char target) {
        int c = 0;
        for (int i = 0; i <= s.length(); i++) {   // bug: <= causes exception; also misses chars
            if (s.charAt(i) == target) c++;
        }
        return c;
    }
    public static void main(String[] args) {
        System.out.println(count("banana", 'a'));
    }
}
